insert into work_hour( id, system, work_month, work_week, work_week_end_date, employee, work_category, type, item, reporter, cost_department, planned_hours, actual_hours, create_time, update_time ) select WORK_HOUR_SEQ.NEXTVAL, t.* from (
select #{item.system} as system, #{item.workMonth} as work_month, #{item.workWeek} as work_week, #{item.workWeekEndDate, jdbcType=VARCHAR} as work_week_end_date, #{item.employee} as employee, #{item.workCategory} as work_category, #{item.type} as type, #{item.item} as item, #{item.reporter} as reporter, #{item.costDepartment} as cost_department, #{item.plannedHours, jdbcType=DOUBLE} as planned_hours, #{item.actualHours, jdbcType=DOUBLE} as actual_hours, sysdate as create_time, sysdate as update_time from dual
) t

mapper.update:
update work_hour
system = #{system}, work_month = #{workMonth}, work_week = #{workWeek}, work_week_end_date = #{workWeekEndDate}, employee = #{employee}, work_category = #{workCategory}, type = #{type}, item = #{item}, reporter = #{reporter}, cost_department = #{costDepartment}, planned_hours = #{plannedHours}, actual_hours = #{actualHours}, update_time = sysdate
where id = #{id}
